import{c as s,Q as n,j as p,m as e}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"容器与镜像:为什么部署不只是上传代码","description":"","frontmatter":{},"headers":[],"relativePath":"cloudBasicsLearning/11-容器与镜像.md","filePath":"cloudBasicsLearning/11-容器与镜像.md","lastUpdated":1779015580000}'),l={name:"cloudBasicsLearning/11-容器与镜像.md"};function i(t,a,c,o,d,r){return n(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="容器与镜像-为什么部署不只是上传代码" tabindex="-1">容器与镜像:为什么部署不只是上传代码 <a class="header-anchor" href="#容器与镜像-为什么部署不只是上传代码" aria-label="Permalink to &quot;容器与镜像:为什么部署不只是上传代码&quot;">​</a></h1><blockquote><p>一句话先记住:镜像是应用运行环境的打包结果,容器是镜像启动后的运行实例。</p></blockquote><p>很多人第一次听到 Docker、容器、镜像,会以为它们只是&quot;新的部署工具&quot;。但容器真正解决的问题不是上传代码,而是&quot;让代码带着它需要的运行环境一起走&quot;。</p><p>同一份代码,在你的电脑能跑,在服务器不能跑,常见原因不是代码变了,而是 Node.js 版本、Python 依赖、系统库、环境变量、文件路径、时区、权限、端口都不一样。容器就是为了解决这种环境不一致。</p><hr><h2 id="一、一句话解释" tabindex="-1">一、一句话解释 <a class="header-anchor" href="#一、一句话解释" aria-label="Permalink to &quot;一、一句话解释&quot;">​</a></h2><p>镜像可以理解成一个只读模板,里面包含应用代码、运行时、依赖包、系统库、启动命令等内容。</p><p>容器可以理解成从这个模板启动出来的进程环境。一个镜像可以启动多个容器,就像一个安装包可以安装出多个运行中的程序。</p><p>它最容易和虚拟机混淆。虚拟机模拟的是一整台机器,里面有完整操作系统内核。容器共享宿主机内核,隔离的是进程、文件系统、网络和资源视图。容器通常更轻,启动更快,但隔离边界也不同于完整虚拟机。</p><p>可以粗略理解成:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>代码:我的应用逻辑</span></span>
<span class="line"><span>镜像:代码 + 运行环境 + 启动方式</span></span>
<span class="line"><span>容器:镜像真正跑起来之后的实例</span></span>
<span class="line"><span>仓库:存放镜像的地方</span></span></code></pre></div><p>容器不是银弹。它解决的是环境一致和交付标准化,不是自动解决架构、性能、安全、备份、监控和成本。</p><hr><h2 id="二、放在系统哪里" tabindex="-1">二、放在系统哪里 <a class="header-anchor" href="#二、放在系统哪里" aria-label="Permalink to &quot;二、放在系统哪里&quot;">​</a></h2><p>容器通常位于计算层内部。</p><p>如果用户访问一个容器化部署的 Web 应用,请求链路可能是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器</span></span>
<span class="line"><span>  -&gt; DNS</span></span>
<span class="line"><span>  -&gt; CDN / WAF</span></span>
<span class="line"><span>  -&gt; 负载均衡 / 反向代理</span></span>
<span class="line"><span>  -&gt; 宿主机上的容器</span></span>
<span class="line"><span>  -&gt; 数据库 / 缓存 / 对象存储</span></span></code></pre></div><p>容器不会替代 DNS、CDN、HTTPS、数据库。它只负责把你的应用进程以标准方式跑起来。</p><p>在一台云服务器上,你可以直接运行应用:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>服务器</span></span>
<span class="line"><span>  -&gt; Node.js / Python / Java</span></span>
<span class="line"><span>  -&gt; 应用进程</span></span></code></pre></div><p>也可以用容器运行:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>服务器</span></span>
<span class="line"><span>  -&gt; Docker / containerd</span></span>
<span class="line"><span>  -&gt; 容器</span></span>
<span class="line"><span>  -&gt; 应用进程</span></span></code></pre></div><p>区别是后者把应用依赖写进镜像构建过程。新服务器只要能运行容器,就可以用同一个镜像启动同一个应用。团队协作时,这会明显减少&quot;我本地是好的&quot;这类问题。</p><p>容器也常出现在 PaaS、Serverless 容器、Kubernetes、CI/CD 里。很多平台虽然界面上只让你连接 Git 仓库,背后也是先构建镜像,再把镜像部署到某种运行环境。</p><hr><h2 id="三、常见套餐和使用限制" tabindex="-1">三、常见套餐和使用限制 <a class="header-anchor" href="#三、常见套餐和使用限制" aria-label="Permalink to &quot;三、常见套餐和使用限制&quot;">​</a></h2><p>容器本身不一定收费,但运行容器的地方会收费。你可能在以下地方遇到限制:</p><ul><li>云服务器上的 Docker</li><li>托管容器平台</li><li>Kubernetes 集群</li><li>Serverless 容器服务</li><li>CI/CD 构建环境</li><li>镜像仓库</li></ul><p>常见限制包括:</p><ul><li>CPU 和内存上限</li><li>容器最大运行时间</li><li>镜像大小</li><li>镜像拉取次数</li><li>构建分钟数</li><li>并发容器数</li><li>出站流量</li><li>日志保留时间</li><li>私有镜像仓库容量</li></ul><p>小团队最容易忽略的是镜像大小和构建时间。一个随便写的 Dockerfile,可能把开发依赖、缓存、测试文件、node_modules、编译中间产物全塞进镜像。结果是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每次部署:</span></span>
<span class="line"><span>  -&gt; 构建慢</span></span>
<span class="line"><span>  -&gt; 上传慢</span></span>
<span class="line"><span>  -&gt; 拉取慢</span></span>
<span class="line"><span>  -&gt; 启动慢</span></span>
<span class="line"><span>  -&gt; CI 构建分钟增加</span></span>
<span class="line"><span>  -&gt; 镜像仓库存储增加</span></span></code></pre></div><p>另一个常见坑是把容器当成数据存储。容器文件系统通常应该被视为临时的。容器重建、迁移、扩容、平台回收时,写在容器内部的文件可能消失。用户上传文件、数据库数据、业务持久化内容,应该放到对象存储、数据库、云盘或明确挂载的持久卷里。</p><p>还有一个坑是环境变量和密钥。容器镜像不应该内置生产数据库密码、API Key、私钥。镜像应该是通用交付物,不同环境通过环境变量、密钥管理或平台配置注入差异。</p><hr><h2 id="四、小团队建议" tabindex="-1">四、小团队建议 <a class="header-anchor" href="#四、小团队建议" aria-label="Permalink to &quot;四、小团队建议&quot;">​</a></h2><p>什么时候应该用容器?</p><ul><li>项目依赖复杂,本地和服务器经常环境不一致</li><li>团队成员多,需要统一开发和部署环境</li><li>一个应用包含多个服务,比如 Web、Worker、定时任务</li><li>需要可重复部署和快速回滚</li><li>未来可能迁移到托管容器平台或 Kubernetes</li></ul><p>什么时候可以先不用?</p><ul><li>只是一个静态站</li><li>只是一个非常简单的脚本或单进程服务</li><li>团队还没有基本 Linux 和网络排障能力</li><li>你只是为了&quot;看起来专业&quot;而容器化</li></ul><p>容器会增加一层抽象。如果连应用本身监听哪个端口、日志输出在哪里、数据库怎么连都没搞清楚,直接上容器只会让排障路径变长。</p><p>对小团队来说,比较务实的路线是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一阶段:</span></span>
<span class="line"><span>  直接部署到 VPS / 云服务器,把端口、进程、日志、反向代理搞清楚</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段:</span></span>
<span class="line"><span>  用 Dockerfile 固化运行环境,用 docker compose 管理本机多服务</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段:</span></span>
<span class="line"><span>  用 CI 构建镜像,推送到镜像仓库,服务器拉取镜像部署</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段:</span></span>
<span class="line"><span>  当服务数量、实例数量、发布频率变复杂后,再考虑托管容器平台或 K8s</span></span></code></pre></div><p>最低限度的实践:</p><ul><li>Dockerfile 不要把密钥写进镜像</li><li>用 <code>.dockerignore</code> 排除无关文件</li><li>尽量让容器无状态</li><li>日志输出到 stdout / stderr,交给平台收集</li><li>配置健康检查</li><li>明确资源限制,不要让一个容器吃完整台机器</li><li>数据库和用户文件不要只放在容器内部</li></ul><p>容器最适合做&quot;交付标准化&quot;,不是用来掩盖应用设计问题。一个会泄露连接、没有超时、没有日志、没有备份的应用,放进容器后仍然是同一个有问题的应用。</p><hr><h2 id="五、一句话总结" tabindex="-1">五、一句话总结 <a class="header-anchor" href="#五、一句话总结" aria-label="Permalink to &quot;五、一句话总结&quot;">​</a></h2><p>镜像让应用和运行环境一起交付,容器让这个交付物以隔离进程的方式运行;小团队应该在环境不一致和部署重复性开始变成真实成本时使用容器,而不是为了追赶技术名词而提前复杂化。</p>`,49)])])}const g=s(l,[["render",i]]);export{u as __pageData,g as default};
